import java.util.ArrayList;import java.util.LinkedHashMap;import java.util.List;import java.util.Map;
final class FlyweightPattern{static final class PatternException extends RuntimeException{private final String code;PatternException(String c){super(c);code=c;}String code(){return code;}}record Metadata(String model,String provider,int contextWindow){}
  static final class Factory{private final Map<String,Metadata>values=new LinkedHashMap<>();void register(Map<String,Object>v){Metadata candidate=new Metadata(String.valueOf(v.get("model")),String.valueOf(v.get("provider")),((Number)v.get("context_window")).intValue());Metadata current=values.get(candidate.model());if(current!=null&&!current.equals(candidate))throw new PatternException("intrinsic_conflict");values.put(candidate.model(),candidate);}Metadata get(String model){Metadata value=values.get(model);if(value==null)throw new PatternException("unknown_model");return value;}int size(){return values.size();}}
  @SuppressWarnings("unchecked")static Object evaluate(Map<String,Object>input){Factory factory=new Factory();for(Map<String,Object>v:(List<Map<String,Object>>)input.getOrDefault("definitions",List.of()))factory.register(v);List<Metadata>values=new ArrayList<>();List<Map<String,Object>>routes=new ArrayList<>();for(Map<String,Object>route:(List<Map<String,Object>>)input.getOrDefault("routes",List.of())){Metadata m=factory.get(String.valueOf(route.get("model")));values.add(m);Map<String,Object>out=new LinkedHashMap<>();out.put("model",m.model());out.put("provider",m.provider());out.put("context_window",m.contextWindow());out.put("tenant",route.get("tenant"));routes.add(out);}boolean reused=values.size()>1;for(int i=1;i<values.size();i++)if(values.get(i)!=values.get(0))reused=false;Map<String,Object>result=new LinkedHashMap<>();result.put("routes",routes);result.put("flyweight_count",factory.size());result.put("reused",reused);return result;}}
